declare var dat: any;


export type Message = {
	type: string,
	data: any
};

export type ClientWSHandler = (data: any) => (Message | void);

export const ReqType = {
	INIT: 'INIT',
	NEW_FIELD: 'NEW_FIELD',
	PLAY: 'PLAY',
	PLAYING: 'PLAYING',
	DONE_PLAYING: 'DONE_PLAYING',
	VALUE_UPDATE: 'VALUE_UPDATE',
};

export interface Folder { obj: any; gui: any; }


let gui;


export class Client {

	ws;
	wsHandlers = new Map<string, ClientWSHandler>();
	folders = new Map<string, Folder>();

	constructor(port: number) {

		// Setup gui for first time
		if (!gui) {
			gui = new dat.GUI({ autoPlace: false });
			let container = document.getElementById('gui-container');
			container.appendChild(gui.domElement);
			gui.width = 400;
		}

		this.ws = new WebSocket('ws://' + window.location.hostname + ':' + port);

		// When the connection is open, send some data to the server
		this.ws.onopen = () => {
			let msg = {
				type: ReqType.INIT,
				data: ''
			};

			this.sendWS(msg);
		};

		this.ws.onclose = (ev) => {
			console.log('WebSocket closed: ', ev);
			this.cleanup();
		};

		// Log errors
		this.ws.onerror = (error) => {
			console.error('WebSocket Error: ', error);
			this.cleanup();
		};

		// Log messages from the server
		this.ws.onmessage = (incoming) => {
			console.log('Got WS message: '+ incoming.data);

			let msg = JSON.parse(incoming.data);
			let handler = this.wsHandlers.get(msg.type);
			if (handler) {
				let resp = handler(msg.data) as Message;
				if (resp) {
					this.sendWS(resp);
				}
			}
		};

		this.addWsHandler(ReqType.VALUE_UPDATE, data => {
			let folder = this.folders.get(data.folderName);
			if (!folder) {
				throw new Error (`No folder of name '${data.folderName}'`);
			}

			folder.obj[data.fieldName] = data.value;

			// Update display value of all children of folder
			folder.gui.__controllers.forEach( (c: any) => {
				c.updateDisplay();
			});
		});

		/**
		 * Install handler for new fields
		 */
		this.addWsHandler(ReqType.NEW_FIELD, data => {
			let folderName = data.folderName;
			let fieldName = data.fieldName;
			let folder = this.folders.get(folderName);
			if (!folder) {
				folder = {
					obj: {},
					gui: gui.addFolder(folderName)
				};
				this.folders.set(folderName, folder);
			}
			folder.gui.open();

			folder.obj[fieldName] = data.field._current;

			let el;
			let type = data.field.type;

			if (type === 'string') {
				el = folder.gui.add(folder.obj, fieldName, data.field.options);
			}
			else if (type === 'boolean'){
				el = folder.gui.add(folder.obj, fieldName);
			}
			else if (type === 'number'){
				el = folder.gui.add(folder.obj, fieldName, data.field.min, data.field.max);
				el.step(data.field.step);
			}
			else if (type === 'button'){
				folder.obj[fieldName] = () => {
					//let a  = arguments;
					//debugger;
					//this.sendWS({
					//	type: ReqType.VALUE_UPDATE,
					//	data: {
					//		folderName,
					//		fieldName,
					//		value: true
					//	}
					//});
				};
				el = folder.gui.add(folder.obj, fieldName);
			}
			else {
				throw new Error(`Can't handle field of type '${data.field.type}'`);
			}

			this.addChangeListener(el, folderName, fieldName);
		});
	}

	sendWS(msg: Message) {
		this.ws.send(JSON.stringify(msg));
	}

	addWsHandler(type: string, handler: ClientWSHandler) {
		this.wsHandlers.set(type, handler);
	}

	addChangeListener(el, folderName, fieldName) {
		el.onChange((value) => {
			this.sendWS({
				type: ReqType.VALUE_UPDATE,
				data: {
					folderName,
					fieldName,
					value,
				}
			});
		});
	}

	cleanup() {
		if (gui) {

			this.folders.forEach( (folder, key) => {
				let clone = folder.gui.__controllers.slice(0);
				clone.forEach( fCon => folder.gui.remove(fCon) );
			});
		}

		this.folders.clear();
		gui.destroy();
		gui  = undefined;
	}
}

const root: any = window || global;
root.Client = Client;