import { Server } from './Server';
import { Folder } from './Folder';
import {
	Field,
	FieldType,
	CheckboxField,
	DropdownField,
	StringField,
	NumberField,
	ButtonField } from './Field';


function shutDownHandler(message: string) {
	Tunable.close();
}

process.on('exit', () => shutDownHandler('process exit') );
process.on('SIGINT', () => shutDownHandler('SIGINT') );
process.on('SIGTERM', () => shutDownHandler('SIGTERM') );

/**
 * Default server port
 * @type {number}
 */
const DEFAULT_PORT = 3333;

let server: Server;


export class Tunable {

	/**
	 * Initialize server at port number
	 * This method is optional but can be used to start a server
	 * at a non-default port, it has to be called before any other
	 * method here.
	 * @param {number} port Server port
	 */
	static initializeServer(port) {
		if (server) {
			server.close();
		}

		server = new Server(port);
		server.start();
	}

	/**
	 * Stops both the web and websocket servers
	 */
	static close() {
		if (server) {
			server.close();
		}
	}

	/**
	 * Gets or starts the server, and then gets or creates a folder
	 * with the requested name
	 * @param name
	 * @returns {Folder}
	 */
	static getFolder(name = ''): Folder {
		if (!server) {
			Tunable.initializeServer(DEFAULT_PORT);
		}

		return server.getFolder(name);
	}

	/**
	 * Creates or gets the already created string field for name
	 * @param {string} name
	 * @param {string} [initial='']
	 * @param {string} [folderName=''] Name of GUI folder to use (empty by default)
	 * @returns {StringField}
	 */
	static getStringField(name: string,
												initial = '',
												folderName = ''): Field<string> {

		let folder = Tunable.getFolder(folderName);
		return folder._installField(name, () => {
			return new StringField(folder, name, initial);
		}) as StringField;
	}

	/**
	 * Creates or gets the already created dropdown field for name
	 * @param {string} name
	 * @param {string[]} options
	 * @param {number} [initialIndex=0]
	 * @param {string} [folderName=''] Name of GUI folder to use (empty by default)
	 * @returns {DropdownField}
	 */
	static getDropdownField(name: string,
													options: string[],
													initialIndex = 0,
													folderName = ''): DropdownField {

		let folder = Tunable.getFolder(folderName);
		return folder._installField(name, () => {
			return new DropdownField(folder, name, options, initialIndex);
		}) as DropdownField;
	}

	/**
	 * Creates (or gets the already created) checkbox field for name
	 * @param {string} name
	 * @param {boolean} [initial=false]
	 * @param {string} [folderName=''] Name of GUI folder to use (empty by default)
	 * @returns {CheckboxField}
	 */
	static getCheckboxField(name: string,
													initial = false,
													folderName = ''): CheckboxField {

		let folder = Tunable.getFolder(folderName);
		return folder._installField(name, () => {
			return new CheckboxField(folder, name, initial);
		}) as CheckboxField;
	}

	/**
	 * Creates (or gets the already created) number field for name
	 * @param {string} name
	 * @param {number} initial Initial value for number
	 * @param {number} min Minimum value for number
	 * @param {number} max Maximum value for number
	 * @param {number} [step=-1] Increments
	 * @param {string} [folderName=''] Name of GUI folder to use (empty by default)
	 * @returns {NumberField}
	 */
	static getNumberField(name: string,
												initial: number,
												min: number,
												max: number,
												step = -1,
												folderName = ''): NumberField {

		let folder = Tunable.getFolder(folderName);
		return folder._installField(name, () => {
			return new NumberField(folder, name, initial, min, max, step);
		}) as NumberField;
	}

	/**
	 * Creates (or gets the already created) trigger button field for name
	 * @param {string} name
	 * @param {string} [folderName=''] Name of GUI folder to use (empty by default)
	 * @returns {ButtonField}
	 */
	static getButtonField(name: string, folderName = ''): ButtonField {
		let folder = Tunable.getFolder(folderName);
		return <ButtonField> folder._installField(name, () => {
			return new ButtonField(folder, name);
		});
	}

	/**
	 * Gets the current value for a field of 'name'
	 * @param {string} name
	 * @param {string} [folderName=''] Name of GUI folder to use (empty by default)
	 * @returns {FieldType}
	 * @throws Error if no such field exists
	 */
	static getValue(name: string, folderName = ''): FieldType {
		let folder = Tunable.getFolder(folderName);
		return folder.getValue(name);
	}
}
