import { Server } from './Server';
import { Field, FieldType } from './Field';


export class Folder {

	fields = new Map<string, Field<any>>();

	constructor(public name: string, public server: Server) { }

	_installField(name: string, creator: ()=>Field<any>): Field<any> {
		let el = this.fields.get(name);
		if (el) {
			return el;
		}

		el = creator();

		this.server.notifyClientOfNewField(null, this.name, name, el);
		this.fields.set(name, el);
		return el;
	}

	getFieldOrThrow(name: string): Field<any> {
		let el = this.fields.get(name);
		if (!el) {
			throw new Error(`No string field named '${name}'`);
		}
		return el;
	}

	getValue(name: string): FieldType {
		return this.getFieldOrThrow(name).current;
	}
}