import * as path from 'path';
import { FileUtils, PromiseUtils } from 'jibo-cai-utils';
let express = require('express');
let ws = require('nodejs-websocket');

import { Field } from './Field';
import { Folder } from './Folder';
import {
	ReqType,
	Message } from './Client';

export type ServerWSHandler = (ws: any, data: any) => (Message | void);

PromiseUtils.catchUnhandledRejection();

const root = FileUtils.getProjectRoot(__dirname);

const shouldLog = false;

function log(...args: any[]) {
	if (shouldLog) {
		let func: Function = console.log;
		func(...args);
	}
}

export class Server {

	public webSocketServer;
	public expressApp = express();
	public httpServer;
	public wsConnections = new Set<any>();

	public wsHandlers = new Map<string, ServerWSHandler>();
	private folders = new Map<string, Folder>();


	constructor(private port: number) {

		/**
		 * Set up Webserver
		 */
		// Handle root
		this.expressApp.get('/', (req, res) => {
			FileUtils.readFile(root + '/public/index.html')
				.then((data:string) => {
					data = data.replace(RegExp('PORT_TO_USE'), '' + (this.port + 1));
					res.send(data);
				})
				.catch(e => res.sendStatus(404));
		});

		// Get certain files from transpiled directory
		this.expressApp.get('/jibo-tunable-client.js', (req: any, res) => {
			let filename = path.basename(req.path);
			log('Request for transpiled file: ' + filename);
			FileUtils.readFile(root + '/lib/' + filename)
				.then((data) => res.send(data))
				.catch(e => res.sendStatus(404));
		});


		// Host files from public directory
		this.expressApp.get('/**.*', (req: any, res) => {
			let filename = path.basename(req.path);
			log('Request for regular file: ' + filename);
			FileUtils.readFile(root + '/public/' + filename)
				.then((data:string) => {
					res.send(data);
				})
				.catch(e => res.sendStatus(404));
		});

		/**
		 * Set up websockets
		 */
		this.webSocketServer = ws.createServer((wsConn) => {
			this.wsConnections.add(wsConn);

			log('WS Connection opened');

			wsConn.on('text', (str) => {
				log('Got WS message: ' + str);

				let req = JSON.parse(str);
				let handler = this.wsHandlers.get(req.type);
				if (handler) {
					let resp = handler(wsConn, req.data) as Message;
					if (resp) {
						this.sendWS(wsConn, resp);
					}
				}
			});

			wsConn.on("close", (code, reason) => {
				this.wsConnections.delete(wsConn);
				log("WS Connection closed");
			});
		});

		/**
		 * Here we add some handlers
		 */

		// On INIT we send all fields to client
		this.addWsMessageHandler(ReqType.INIT, (wsConn, data) => {
			this.folders.forEach( (folder, folderName) => {
				folder.fields.forEach( (field, fieldName) => {
					this.notifyClientOfNewField(wsConn, folderName, fieldName, field);
				});
			});
		});

		// On value update we update values
		this.addWsMessageHandler(ReqType.VALUE_UPDATE, (wsConn, data) => {
			let folder = this.folders.get(data.folderName);
			if (!folder) {
				throw new Error(`No folder of name '${data.folderName}'`);
			}

			let field = folder.fields.get(data.fieldName);
			if (!field) {
				throw new Error(`No field of name '${data.fieldName}'`);
			}

			field._setCurrent(data.value, true);
		});

	}

	notifyClientOfNewField(wsConn, folderName: string,
												 fieldName: string,
												 field: Field<any>) {
		let msg = {
			type: ReqType.NEW_FIELD,
			data: {
				folderName,
				fieldName,
				field: field.toSimpleObject(),
			}
		};

		if (wsConn) {
			this.sendWS(wsConn, msg);
		}
		else {
			this.wsConnections.forEach( _wsConn => {
				this.sendWS(_wsConn, msg);
			});
		}
	}

	getFolder(name: string): Folder {
		let nameToUse = (name === '') ? 'Tunable Parameters' : name;

		let folder = this.folders.get(nameToUse);
		if (!folder) {
			folder = new Folder(nameToUse, this);
			this.folders.set(nameToUse, folder);
		}

		return folder;
	}

	start() {
		const errHandler = e => {
			console.error(`jibo-tunable error: `, e);
			this.close();
		};

		// Start servers
		this.httpServer = this.expressApp.listen(this.port);
		this.httpServer.on('error', errHandler);

		this.webSocketServer.listen(this.port + 1);
		this.webSocketServer.on('error', errHandler);

		log('Tunable server started on port ' + this.port);
	}

	close() {
		if (this.httpServer) {
			this.httpServer.close();
			this.httpServer = null;
		}
		if (this.webSocketServer) {
			this.webSocketServer.close();
			this.webSocketServer = null;
		}
	}

	broadcastWS(msg: Message) {
		this.wsConnections.forEach( ws => {
			this.sendWS(ws, msg);
		});
	}

	sendWS(wsConn, msg: Message) {
		let json = JSON.stringify(msg);
		if (!wsConn) {
			this.wsConnections.forEach( _wsConn => {
				_wsConn.sendText(json);
			});
		}
		else {
			wsConn.sendText(json);
		}
	}

	addWsMessageHandler(type: string, handler: ServerWSHandler) {
		this.wsHandlers.set(type, handler);
	}
}
