import { Event, EventContainer } from 'jibo-typed-events';

import { Folder } from './Folder';
import { ReqType } from './Client';


export type FieldType = ( string | number | boolean );
export type FieldTypeString = ( 'string' | 'number' | 'boolean' | 'button' );


export class FieldEvents<ValidType> extends EventContainer {

	change = new Event<ValidType>('Value change');

	constructor() {
		super();
	}
}


export abstract class Field <ValidType> {

	events = new FieldEvents<ValidType>();
	protected _current: ValidType;
	protected _limitInput: (input: ValidType) => ValidType;

	constructor(public folder: Folder, public name: string, public initial: ValidType, public type: FieldTypeString) {
		this._setCurrent(initial, false, true);
	}

	public get current() {
		return this._current;
	}

	public set current(value: ValidType) {
		this._setCurrent(value, false);
	}

	public _setCurrent(value: ValidType, fromRemote: boolean, noChange=false) {
		let forceChangeEvent = false;
		if (this._limitInput) {
			value = this._limitInput(value);
			if (value === null) {
				forceChangeEvent = true;
			}
		}

		const change = this._current !== value;
		this._current = value;

		if (!fromRemote) {
			this._updateRemote();
		}

		if ((forceChangeEvent || change) && !noChange) {
			this.events.change.emit(this._current);
		}
	}

	protected _updateRemote() {
		// Update remote
		this.folder.server.sendWS(null, {
			type: ReqType.VALUE_UPDATE,
			data: {
				fieldName: this.name,
				folderName: this.folder.name,
				value: this._current
			}
		});
	}


	/**
	 * Returns a basic representation of this element for serialization
	 * @returns {any}
	 */
	toSimpleObject() {
		let out: any = {};
		for (let attr of Object.keys(this)) {
			if (attr !== 'events' && attr !== 'folder') {
				out[attr] = this[attr];
			}
		}
		return out;
	}
}


export class StringField extends Field<string> {

	constructor(folder: Folder, name: string, public initial = '') {
		super(folder, name, initial, 'string');
	}
}


export class DropdownField extends Field<string> {

	constructor(folder: Folder, name: string,
							public options: string[], initialIndex = 0) {
		super(folder, name, (options[initialIndex] || ''), 'string' );

		if (initialIndex < 0 || initialIndex >= options.length) {
			throw Error(`Tunable: '${this.folder.name}/${this.name}' initial index ${initialIndex} out of bounds`);
		}

		this._limitInput = (input: string) => {
			const index = options.indexOf(input);
			if (index === -1) {
				console.warn(`Tunable: '${this.folder.name}/${this.name}' input ${input} not a valid option, skipping`);
				input = this.current;
			}

			return input;
		};
	}
}


export class CheckboxField extends Field<boolean> {

	constructor(folder: Folder, name: string, public initial = false) {
		super(folder, name, initial, 'boolean');
	}
}


export class NumberField extends Field<number> {

	constructor(folder: Folder,
							name: string,
							public initial = 0,
							public min: number,
							public max: number,
							public step = -1) {
		super(folder, name, initial, 'number');

		if (min > initial || max < initial) {
			throw new Error(`Invalid bounds, min: ${min}, max: ${max}, initial: ${initial}`);
		}

		if (step === -1) {
			this.step = (max - min) / 100;
		}

		this._limitInput = (input: number) => {
			if (input < this.min) {
				console.warn(`Tunable: '${this.folder.name}/${this.name}' input ${input} lower than min ${this.min}, capping`);
				input = this.min;
			}
			else if (input > this.max) {
				console.warn(`Tunable: '${this.folder.name}/${this.name}' input ${input} higher than max ${this.max}, capping`);
				input = this.max;
			}

			return input;
		};
	}

	// Not supported in Typescript yet (getter/setter of subclass https://github.com/Microsoft/TypeScript/issues/338)
	// set current(value) {
	// 	if (value < this.min || value > this.max) {
	// 		throw new Error(`Value '${value}' is not within bounds '[${this.min}, ${this.max}]'`);
	// 	}
	// 	super.current = value;
	// }
}

export class ButtonField extends Field<boolean> {

	constructor(folder:Folder, name:string) {
		super(folder, name, false, 'button');

		// Sending null to enforce a change event
		this._limitInput = () => {
			return null;
		};
	}

	press() {
		this.current = true;
	}
}